code.C:
#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, s;
        scanf("%d %d", &n, &s);
        int ideal_sum = n * (n + 1) / 2;
        printf("%d\n", (s < ideal_sum) ? (ideal_sum - s) : 0);
    }
    return 0;
}

