code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int s = sc.nextInt();
            int ideal_sum = n * (n + 1) / 2;
            System.out.println((s < ideal_sum) ? (ideal_sum - s) : 0);
        }
    }
}

